+        private async Task<bool> UpdateCompanyForUserAsync(IDBHelper portfolioDB, UserMaintenance user, RecordChangeUser recordChange, IRequestedBy requestedBy, ErrorEncountered error, CancellationToken cancellationToken)
+        {
+            // Exceptions are handled by the caller
+
+            // If the company has not changed, we are done
+            var newCompanyID = Global.IntFromDB(recordChange.Fields[nameof(UserMaintenance.CompanyID)]);
+            if (newCompanyID == user.CompanyID)
+            {
+                return true;
+            }
+
+            // it has changed, so we need to generate a new record change that will only affect the contact
+
+            var recordChangeUser = new RecordChangeUser()
+            {
+                PrimaryKey = user.ContactID,
+            };
+
+            // Keep track of the original company details
+            var originalCompany = new Company
+            {
+                CompanyID = user.CompanyID,
+                Name = user.CompanyName,
+                GUID = user.CompanyGuid
+            };
+
+            recordChangeUser.AddFieldIfSet(nameof(Contact.CompanyID), user.CompanyID, FieldAttribute.FormatTypes.Integer, requestedBy.User);
+            recordChangeUser.AddFieldIfSet(nameof(Contact.ContactID), user.ContactID, FieldAttribute.FormatTypes.Integer, requestedBy.User);
+            recordChangeUser.AddFieldIfSet(nameof(Contact.GUID), user.GUIDAsString, FieldAttribute.FormatTypes.String, requestedBy.User);
+            recordChangeUser.AddFieldIfSet(nameof(Contact.NewCompanyID), newCompanyID, FieldAttribute.FormatTypes.Integer, requestedBy.User);
+
+            var teamMemberChangeRequest = new UpdateTeamMemberChangeRequest
+            {
+                ContactID = user.ContactID,
+                RecordChangeUser = recordChangeUser,
+                ColumnName = nameof(Contact.CompanyID),
+            };
+
+            await new TeamMemberSystem().UpdateTeamMemberInternalAsync(portfolioDB, teamMemberChangeRequest, error, cancellationToken);
+
+            var result = !error.HasMessage;
+            if (result)
+            {
+                // create history for the contact
+                AddHistoryForContactMovedToDifferentCompany(portfolioDB, user.ContactID, originalCompany);
+            }
+            else
+            {
+                // change the error message if this is happening when changing the company in the user
+                if (error.Code == (int)NomenclatureMaster.AllApplicationErrors.RecordIsNotEditable)
+                {
+                    user.HandleError((int)UserMaintenance.ErrorMessages.No_Authority_To_Change_Company, error, new ErrorTextRequest(portfolioDB));
+                }
+            }
+
+            return result;
+        }
