+                using (var reader = portfolioDB.ExecuteReader($"SELECT * FROM fn_enc_get_ContactsProjectsLinks_ChildRecords({contactId}, 0)"))
+                {
+                    contact.Projects.AddRecordsFromDataReaderNoUDFs(reader);
