+/****** Object:  Stored Procedure s_enc_verify_contact_CompanyID_change ******/
+CREATE PROCEDURE dbo.s_enc_verify_contact_CompanyID_change
+  @ContactID        int,
+  @CompanyIDCannotBeChanged bit = 0 OUTPUT
+AS
+  SET @CompanyIDCannotBeChanged =
+     CASE WHEN EXISTS(SELECT 1 FROM ApplicationForPay r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR ToSignedByContactID = @ContactID OR FromContactID = @ContactID OR FromSignedByContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM ChangeOrderRequests r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR FromContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM ContractInvoices r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR ToSignedByContactID = @ContactID OR FromContactID = @ContactID OR FromSignedByContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM Contracts r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR ToSignedByContactID = @ContactID OR FromContactID = @ContactID OR FromSignedByContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM GeneralInvoices r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR FromContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM Labor r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM PrimeContractCO r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR ToSignedByContactID = @ContactID OR FromContactID = @ContactID OR FromSignedByContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM PurchaseOrders r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR FromContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM SubcontractCO r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR ToSignedByContactID = @ContactID OR FromContactID = @ContactID OR FromSignedByContactID = @ContactID)) THEN 1
+          WHEN EXISTS(SELECT 1 FROM Transmittals r INNER JOIN Projects p ON r.ProjectID = p.ProjectID WHERE r.Deleted = 0 AND p.Deleted = 0 AND (ToContactID = @ContactID OR FromContactID = @ContactID OR AcknowledgedByContactID = @ContactID)) THEN 1
+          ELSE 0
+      END
+GO
