+AS
+   /* This data group is used to provide the site capture station links for reporting */
+   /* ONLY THE MOST RECENT LINK TO ANY TARGET IS RETURNED */
+  RETURN
+  SELECT *
+    FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY r.LinkedRecordGUID, r.SiteCaptureStationId ORDER BY WhenCreated desc) AS RowNum,
+                  r.* ,
+                  LinkedTableName = CAST(NULL AS NVARCHAR(MAX)) ,
+                  LinkedTableImage = CAST(NULL AS NVARCHAR(MAX)) ,
+                  CAST(NULL AS INT) AS LinkedRecordId ,
