+                  CAST(NULL AS NVARCHAR(150)) AS RecordGroup ,
+                  CAST(NULL AS NVARCHAR(50)) AS RevisionNumber ,
+                  CAST(NULL AS DATETIMEOFFSET) AS RevisionDate ,
+                  CAST(NULL AS NVARCHAR(255)) AS DrawingSetName ,
+                  CAST(NULL AS VARBINARY(MAX)) AS Thumbnail
